Thanks for taking the time to report this.

Can you attach an example that shows the issue?  (Must be openly licensed, completely self-contained and self-checking so can directly run what you provide. Ideally use test_regress format, see https://veripool.org/guide/latest/contributing.html?highlight=test_regress#reporting-bugs

```
package s_pkg;
class s_d2h_data_agent_cfg;  
  virtual s_d2h_data_if  c_vif;
endclass: s_d2h_data_agent_cfg
endpackage : s_pkg
interface s_d2h_data_if
  #()
  (input wire sys_clk);
   logic  crd;
   logic  hdr;
   logic  chk;
  clocking mst_cb @(posedge sys_clk);
    default input #1step output #0.1ns;
    input  crd;
    output hdr;    
    output chk;
  endclocking : mst_cb
  clocking slv_cb @(posedge sys_clk);
    default input #1step output #0.1ns;
    output crd;
    input  hdr;    
    input  chk;
  endclocking : slv_cb
  covergroup d2h_data_covergroup @(posedge sys_clk);    
    option.per_instance = 1;
    C1:coverpoint crd;
    C2:coverpoint hdr {bins data_hdr [1000] = {[0:$]};}
    C3:coverpoint chk {option.auto_bin_max = 100;}  
  endgroup:d2h_data_covergroup
endinterface : s_d2h_data_if
module tb_top;
endmodule : tb_top
```

